好的，我可以提供一个基于Java的简单贪吃蛇游戏的代码示例。以下是一个简单的贪吃蛇游戏示例，仅供参考：

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;
import java.util.*;

public class SnakeGame extends JFrame implements ActionListener {
    private Random rand = new Random();
    private Timer timer;
    private JPanel gamePanel;
    private JLabel statusLabel;
    private int width = 30, height = 30;
    private int[][] grid = new int[width][height];
    private int length = 3;
    private ArrayList<Point> snake = new ArrayList<Point>();
    private Point food = new Point(rand.nextInt(width), rand.nextInt(height));
    private int dx = 1, dy = 0;

    public SnakeGame() {
        setTitle("Snake Game");
        setDefaultCloseOperation(EXIT_ON_CLOSE);
        setSize(400, 400);
        setLocationRelativeTo(null);
        setResizable(false);
        init();
        setVisible(true);
    }

    private void init() {
        gamePanel = new JPanel();
        gamePanel.setLayout(new GridLayout(height, width));
        for (int i = 0; i < height; i++) {
            for (int j = 0; j < width; j++) {
                grid[i][j] = 0;
                gamePanel.add(new JLabel(new ImageIcon("blank.png")));
            }
        }
        getContentPane().add(gamePanel, BorderLayout.CENTER);
        statusLabel = new JLabel("Score: 0");
        getContentPane().add(statusLabel, BorderLayout.SOUTH);
        snake.add(new Point(width / 2, height / 2));
        for (int i = 1; i < length; i++) {
            snake.add(new Point(width / 2 - i, height / 2));
            grid[height / 2][width / 2 - i] = i;
        }
        updateSnake();
        timer = new Timer(200, this);
        timer.start();
        addKeyListener(new KeyAdapter() {
            public void keyPressed(KeyEvent e) {
                if (e.getKeyCode() == KeyEvent.VK_LEFT && dx == 0) {
                    dx = -1;
                    dy = 0;
                } else if (e.getKeyCode() == KeyEvent.VK_RIGHT && dx == 0) {
                    dx = 1;
                    dy = 0;
                } else if (e.getKeyCode() == KeyEvent.VK_UP && dy == 0) {
                    dx = 0;
                    dy = -1;
                } else if (e.getKeyCode() == KeyEvent.VK_DOWN && dy == 0) {
                    dx = 0;
                    dy = 1;
                }
            }
        });
        setFocusable(true);
    }

    public void actionPerformed(ActionEvent e) {
        int x = snake.get(0).x + dx;
        int y = snake.get(0).y + dy;
        if (x < 0) x += width;
        if (x >= width) x -= width;
        if (y < 0) y += height;
        if (y >= height) y -= height;
        if (grid[y][x] != 0) gameOver();
        if (x == food.x && y == food.y) {
            length++;
            statusLabel.setText("Score: " + (length - 3));
            food.setLocation(rand.nextInt(width), rand.nextInt(height));
        } else {
            int tailX = snake.get(snake.size() - 1).x;
            int tailY = snake.get(snake.size() - 1).y;
            grid[tailY][tailX] = 0;
            snake.remove(snake.size() - 1);
        }
        snake.add(0, new Point(x, y));
        grid[y][x] = 1;
        updateSnake();
    }

    private void updateSnake() {
        for (int i = 0; i < height; i++) {
            for (int j = 0; j < width; j++) {
                if (grid[i][j] == 0) {
                    ((JLabel)gamePanel.getComponent(i * width + j)).setIcon(new ImageIcon("blank.png"));
                } else if (grid[i][j] == 1) {
                    ((JLabel)gamePanel.getComponent(i * width + j)).setIcon(new ImageIcon("snake.png"));
                }
            }
        }
        ((JLabel)gamePanel.getComponent(food.y * width + food.x)).setIcon(new ImageIcon("food.png"));
    }

    private void gameOver() {
        statusLabel.setText("Game Over!");
        timer.stop();
    }

    public static void main(String[] args) {
        new SnakeGame();
    }
}
```

这是一个非常基本的示例，可供您参考。它使用Java Swing库来创建窗体和图形界面，并使用Timer类来实现游戏循环。游戏板由一个二维数组表示，在游戏循环中进行刷新，并根据键盘事件处理来设置蛇的移动方向。
